//! Spec-compliance tests: Tables (ISO 29500-1 §17.4)
//!
//! These tests verify our implementation against specific OOXML table
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/tables";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

fn cell_text(table: &stemma::TableNode, row: usize, col: usize) -> String {
    let cell = &table.rows[row].cells[col];
    let mut text = String::new();
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            let inlines = p.all_inlines_owned();
            for inline in &inlines {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

// ── tblCellMar / tcMar ──────────────────────────────────────────────────

/// ISO 29500-1 §17.4.42/43: Table cell margins (global and per-cell).
#[test]
fn spec_cell_margins_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-margins");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
}

/// Cell margins should be exposed in the domain model.
#[test]
fn spec_cell_margins_is_exposed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-margins");
    let table = first_table(&doc);

    // Table-level default margins: top=100, left=200, bottom=100, right=200
    let default_margins = table
        .formatting
        .default_cell_margins
        .as_ref()
        .expect("table should have default_cell_margins from tblCellMar");
    assert_eq!(default_margins.top, Some(100));
    assert_eq!(default_margins.left, Some(200));
    assert_eq!(default_margins.bottom, Some(100));
    assert_eq!(default_margins.right, Some(200));

    // Cell (1,0) overrides: top=200, left=400, bottom=200, right=400
    let cell_margins = table.rows[1].cells[0]
        .formatting
        .margins
        .as_ref()
        .expect("cell (1,0) should have per-cell margin overrides from tcMar");
    assert_eq!(cell_margins.top, Some(200));
    assert_eq!(cell_margins.left, Some(400));
    assert_eq!(cell_margins.bottom, Some(200));
    assert_eq!(cell_margins.right, Some(400));
}

// ── trHeight ────────────────────────────────────────────────────────────

/// ISO 29500-1 §17.4.81: Row height with height rules.
#[test]
fn spec_row_height_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "row-height");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 3, "should have 3 rows");
}

/// Row height values and rules should be exposed.
#[test]
fn spec_row_height_is_exposed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "row-height");
    let table = first_table(&doc);

    // Row 0: no explicit height (auto)
    assert_eq!(
        table.rows[0].height, None,
        "row 0 should have no explicit height"
    );
    assert_eq!(
        table.rows[0].height_rule, None,
        "row 0 should have no height rule"
    );

    // Row 1: height=1440 twips, rule=exact
    assert_eq!(
        table.rows[1].height,
        Some(1440),
        "row 1 height should be 1440 twips"
    );
    assert_eq!(
        table.rows[1].height_rule,
        Some(stemma::domain::HeightRule::Exact),
        "row 1 height rule should be 'exact'"
    );

    // Row 2: height=720 twips, rule=atLeast
    assert_eq!(
        table.rows[2].height,
        Some(720),
        "row 2 height should be 720 twips"
    );
    assert_eq!(
        table.rows[2].height_rule,
        Some(stemma::domain::HeightRule::AtLeast),
        "row 2 height rule should be 'atLeast'"
    );
}

// ── tblStyle ────────────────────────────────────────────────────────────

/// ISO 29500-1 §17.4.63: Table style reference.
#[test]
fn spec_tbl_style_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-style");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
}

/// Table style should be resolved and formatting applied.
///
/// The table references style "LegalTable" which defines single/4pt/000000 borders
/// on all 6 edges (top, bottom, left, right, insideH, insideV).
/// These should appear in the table's formatting even though the table element
/// has no direct tblBorders.
#[test]
fn spec_tbl_style_is_resolved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-style");
    let table = first_table(&doc);

    let borders = table
        .formatting
        .borders
        .as_ref()
        .expect("table should have borders inherited from LegalTable style");

    // LegalTable defines all 6 edges as single/sz=4/color=000000.
    for (name, edge) in [
        ("top", &borders.top),
        ("bottom", &borders.bottom),
        ("left", &borders.left),
        ("right", &borders.right),
        ("insideH", &borders.inside_h),
        ("insideV", &borders.inside_v),
    ] {
        let border = edge
            .as_ref()
            .unwrap_or_else(|| panic!("border edge '{name}' should be present"));
        assert_eq!(
            border.style,
            stemma::domain::BorderStyle::Single,
            "{name} border style"
        );
        assert_eq!(border.size, Some(4), "{name} border size");
        assert_eq!(
            border.color.as_deref(),
            Some("000000"),
            "{name} border color"
        );
    }
}

// ── tblHeader ───────────────────────────────────────────────────────────

/// ISO 29500-1 §17.4.50: Header row repeat.
#[test]
fn spec_tbl_header_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-header");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 4, "should have 4 rows");
}

/// The tblHeader flag should be exposed on header rows.
#[test]
fn spec_tbl_header_is_exposed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-header");
    let table = first_table(&doc);

    // Row 0 has tblHeader = true
    assert!(table.rows[0].is_header, "row 0 should be a header row");

    // Rows 1-3 do not have tblHeader
    for i in 1..table.rows.len() {
        assert!(
            !table.rows[i].is_header,
            "row {} should not be a header row",
            i
        );
    }
}

// ── Complex cell merges ─────────────────────────────────────────────────

/// Complex vertical + horizontal merge pattern.
///
/// Grid layout:
///   Row 0: [A (2x2 merged)] [C]
///   Row 1: [A (continue)]   [D]
///   Row 2: [E] [F]          [G]
///
/// The canonical table should correctly resolve the owner grid.
#[test]
fn spec_complex_merge_is_canonicalized() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-merge");
    let table = first_table(&doc);

    // Basic structure check
    assert!(
        table.rows.len() >= 3,
        "should have at least 3 rows, got {}",
        table.rows.len()
    );

    // Row 0 should have fewer physical cells due to gridSpan
    assert!(
        table.rows[0].cells.len() <= 3,
        "row 0 should have at most 3 physical cells (merged), got {}",
        table.rows[0].cells.len()
    );

    // Verify that cell A's text is accessible
    let row0_texts: Vec<String> = (0..table.rows[0].cells.len())
        .map(|c| cell_text(table, 0, c))
        .collect();
    let has_merged_cell = row0_texts.iter().any(|t| t.contains("merged"));
    assert!(
        has_merged_cell,
        "row 0 should contain the merged cell 'A (merged 2x2)', got: {:?}",
        row0_texts
    );

    // Row 2 should have 3 separate cells (E, F, G)
    let row2_texts: Vec<String> = (0..table.rows[2].cells.len())
        .map(|c| cell_text(table, 2, c))
        .collect();
    assert!(
        row2_texts.iter().any(|t| t.contains('E')),
        "row 2 should contain 'E', got: {:?}",
        row2_texts
    );
    assert!(
        row2_texts.iter().any(|t| t.contains('G')),
        "row 2 should contain 'G', got: {:?}",
        row2_texts
    );
}

// ── gridBefore / gridAfter ──────────────────────────────────────────────

/// ISO 29500-1 §17.4.14/3: Staggered table layouts.
///
/// Row 0: 4 cells (A1-D1)
/// Row 1: gridBefore=1, 3 cells at positions 1-3 (B2-D2)
/// Row 2: gridAfter=1, 3 cells at positions 0-2 (A3-C3)
#[test]
fn spec_grid_before_after_parses() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "grid-before-after");
    let table = first_table(&doc);

    // Row 0: 4 cells
    assert_eq!(table.rows[0].cells.len(), 4, "row 0 should have 4 cells");

    // Row 1: 3 cells (gridBefore=1 offsets them)
    assert_eq!(
        table.rows[1].cells.len(),
        3,
        "row 1 should have 3 physical cells (gridBefore=1 offsets by 1)"
    );

    // Row 2: 3 cells (gridAfter=1 leaves 1 empty at end)
    assert_eq!(
        table.rows[2].cells.len(),
        3,
        "row 2 should have 3 physical cells (gridAfter=1)"
    );
}

/// gridBefore should correctly position cells in the canonical grid.
#[test]
fn spec_grid_before_cell_positioning() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "grid-before-after");
    let table = first_table(&doc);

    // Row 1's first cell content should be B2 (offset by 1 grid column)
    let row1_first = cell_text(table, 1, 0);
    assert!(
        row1_first.contains("B2"),
        "row 1 first cell should contain 'B2' (offset by gridBefore=1), got: '{}'",
        row1_first
    );

    // Row 2's cells should start at position 0
    let row2_first = cell_text(table, 2, 0);
    assert!(
        row2_first.contains("A3"),
        "row 2 first cell should contain 'A3', got: '{}'",
        row2_first
    );
}
